export const ASSET_INDEX = Object.freeze(
    ASSET_MANIFEST.reduce((acc, a) => { acc[a.id] = a; return acc; }, {})
);

export const CATEGORIES = ['terrain', 'nature', 'props', 'water', 'buildings'];
